solution:
# Problem: Implement a mini test discovery and runner system similar to pytest.
# It discovers test_* functions from a namespace dict, runs them with optional
# setup/teardown hooks, and collects results into a report.
#
# Approach:
# - collect() scans the namespace for callable test_* items and special hooks
# - run() orchestrates execution: module setup, per-test setup/run/teardown, module teardown
# - Use try/finally to guarantee teardown calls even when tests raise exceptions
#
# Time complexity: O(n log n) for sorting tests, O(n) for running them
# Space complexity: O(n) for storing test results
#
# Key steps:
# 1. Filter namespace for callable items starting with "test_", sort alphabetically
# 2. Capture setup_module, teardown_module, setup_function, teardown_function if present
# 3. Run tests in order, wrapping each in try/finally for teardown_function
# 4. Wrap entire run in try/finally for teardown_module
# 5. Collect TestResult objects into a RunReport


class TestResult:
    def __init__(self, name: str, passed: bool, error: str | None = None):
        self.name = name
        self.passed = passed
        self.error = error


class RunReport:
    def __init__(self, results: list):
        self.results = results

    @property
    def total(self) -> int:
        return len(self.results)

    @property
    def passed_count(self) -> int:
        return sum(1 for r in self.results if r.passed)

    @property
    def failed_count(self) -> int:
        return sum(1 for r in self.results if not r.passed)

    def summary(self) -> str:
        return f"{self.passed_count} passed, {self.failed_count} failed, {self.total} total"


class TestRunner:
    def __init__(self):
        self.tests = []
        self.setup_module = None
        self.teardown_module = None
        self.setup_function = None
        self.teardown_function = None

    def collect(self, namespace: dict):
        # Scan namespace for test functions and setup/teardown hooks
        self.tests = sorted(
            [(name, func) for name, func in namespace.items()
             if callable(func) and name.startswith("test_")],
            key=lambda t: t[0]
        )
        # Capture optional hooks if they exist and are callable
        for hook_name in ("setup_module", "teardown_module", "setup_function", "teardown_function"):
            func = namespace.get(hook_name)
            if func is not None and callable(func):
                setattr(self, hook_name, func)

    def run(self):
        # Execute collected tests with setup/teardown, return RunReport
        results = []
        if self.setup_module:
            self.setup_module()
        try:
            for name, test_func in self.tests:
                if self.setup_function:
                    self.setup_function()
                try:
                    test_func()
                    results.append(TestResult(name, passed=True))
                except Exception as e:
                    # Capture the error message for the report
                    results.append(TestResult(name, passed=False, error=str(e)))
                finally:
                    # teardown_function runs even if the test raised
                    if self.teardown_function:
                        self.teardown_function()
        finally:
            # teardown_module runs even if tests failed
            if self.teardown_module:
                self.teardown_module()
        return RunReport(results)
